// ════════════════════════════════════════════════════════════════
// 🔒 v2.K.5 — Replan + Parallel Integration Stability Test
// ════════════════════════════════════════════════════════════════
// 실행 중 Replan 발생 시: DAG 정합성 + Race condition 없음 증명

// ─────────────────────────────────────────────────────────────
// Integration Constants
// ─────────────────────────────────────────────────────────────

let POLICY_DECISION_PROCEED = 1
let POLICY_DECISION_RETRY = 2
let POLICY_DECISION_REPLAN = 3
let POLICY_DECISION_ABORT = 4

let SCHEDULER_STRATEGY_FIFO = 1
let SCHEDULER_STRATEGY_PRIORITY = 2

// ─────────────────────────────────────────────────────────────
// Unified State Tracking (Kernel 중립)
// ─────────────────────────────────────────────────────────────

let GLOBAL_PARALLEL_POLICY_MAX = 3
let GLOBAL_RUNNING_TASKS_COUNT = 0
let GLOBAL_READY_TASKS_COUNT = 0

let GLOBAL_RUNNING_1 = ""
let GLOBAL_RUNNING_2 = ""
let GLOBAL_RUNNING_3 = ""

let GLOBAL_READY_1 = ""
let GLOBAL_READY_2 = ""
let GLOBAL_READY_3 = ""
let GLOBAL_READY_4 = ""
let GLOBAL_READY_5 = ""
let GLOBAL_READY_6 = ""

let GLOBAL_TASKS_COMPLETED = 0
let GLOBAL_TASKS_FAILED = 0
let GLOBAL_REPLANS_ATTEMPTED = 0
let GLOBAL_REPLANS_SUCCEEDED = 0

// ─────────────────────────────────────────────────────────────
// Running Pool Management (Parallel 상태)
// ─────────────────────────────────────────────────────────────

fn RunningPool_add(task_id) {
  if GLOBAL_RUNNING_TASKS_COUNT >= GLOBAL_PARALLEL_POLICY_MAX {
    return false
  }

  GLOBAL_RUNNING_TASKS_COUNT = GLOBAL_RUNNING_TASKS_COUNT + 1

  if GLOBAL_RUNNING_TASKS_COUNT == 1 { GLOBAL_RUNNING_1 = task_id }
  if GLOBAL_RUNNING_TASKS_COUNT == 2 { GLOBAL_RUNNING_2 = task_id }
  if GLOBAL_RUNNING_TASKS_COUNT == 3 { GLOBAL_RUNNING_3 = task_id }

  return true
}

fn RunningPool_remove(task_id) {
  let found = false
  let i = 1

  while i <= GLOBAL_RUNNING_TASKS_COUNT {
    if !found {
      let running_id = ""
      if i == 1 { running_id = GLOBAL_RUNNING_1 }
      if i == 2 { running_id = GLOBAL_RUNNING_2 }
      if i == 3 { running_id = GLOBAL_RUNNING_3 }

      if running_id == task_id {
        found = true

        if i < GLOBAL_RUNNING_TASKS_COUNT {
          let next_id = ""
          if i == 1 {
            next_id = GLOBAL_RUNNING_2
            GLOBAL_RUNNING_1 = GLOBAL_RUNNING_2
            GLOBAL_RUNNING_2 = GLOBAL_RUNNING_3
          }
          if i == 2 {
            next_id = GLOBAL_RUNNING_3
            GLOBAL_RUNNING_2 = GLOBAL_RUNNING_3
          }
        }

        if GLOBAL_RUNNING_TASKS_COUNT == 1 { GLOBAL_RUNNING_1 = "" }
        if GLOBAL_RUNNING_TASKS_COUNT == 2 { GLOBAL_RUNNING_2 = "" }
        if GLOBAL_RUNNING_TASKS_COUNT == 3 { GLOBAL_RUNNING_3 = "" }

        GLOBAL_RUNNING_TASKS_COUNT = GLOBAL_RUNNING_TASKS_COUNT - 1
      }
    }

    i = i + 1
  }

  return found
}

fn RunningPool_length() {
  return GLOBAL_RUNNING_TASKS_COUNT
}

// ─────────────────────────────────────────────────────────────
// Ready Queue Management (DAG 상태)
// ─────────────────────────────────────────────────────────────

fn ReadyQueue_add(task_id) {
  if GLOBAL_READY_TASKS_COUNT >= 6 {
    return false
  }

  GLOBAL_READY_TASKS_COUNT = GLOBAL_READY_TASKS_COUNT + 1

  if GLOBAL_READY_TASKS_COUNT == 1 { GLOBAL_READY_1 = task_id }
  if GLOBAL_READY_TASKS_COUNT == 2 { GLOBAL_READY_2 = task_id }
  if GLOBAL_READY_TASKS_COUNT == 3 { GLOBAL_READY_3 = task_id }
  if GLOBAL_READY_TASKS_COUNT == 4 { GLOBAL_READY_4 = task_id }
  if GLOBAL_READY_TASKS_COUNT == 5 { GLOBAL_READY_5 = task_id }
  if GLOBAL_READY_TASKS_COUNT == 6 { GLOBAL_READY_6 = task_id }

  return true
}

fn ReadyQueue_peek() {
  if GLOBAL_READY_TASKS_COUNT > 0 {
    return GLOBAL_READY_1
  }
  return ""
}

fn ReadyQueue_dequeue() {
  if GLOBAL_READY_TASKS_COUNT == 0 {
    return ""
  }

  let first = GLOBAL_READY_1

  GLOBAL_READY_1 = GLOBAL_READY_2
  GLOBAL_READY_2 = GLOBAL_READY_3
  GLOBAL_READY_3 = GLOBAL_READY_4
  GLOBAL_READY_4 = GLOBAL_READY_5
  GLOBAL_READY_5 = GLOBAL_READY_6
  GLOBAL_READY_6 = ""

  GLOBAL_READY_TASKS_COUNT = GLOBAL_READY_TASKS_COUNT - 1

  return first
}

fn ReadyQueue_length() {
  return GLOBAL_READY_TASKS_COUNT
}

// ─────────────────────────────────────────────────────────────
// PlanDelta Application (DAG 변경)
// ─────────────────────────────────────────────────────────────

fn applyPlanDelta_addTask(new_task_id) {
  // 새로운 Task를 Ready에 추가
  // Running Task들은 그대로 계속 실행
  let added = ReadyQueue_add(new_task_id)

  if added {
    GLOBAL_REPLANS_SUCCEEDED = GLOBAL_REPLANS_SUCCEEDED + 1
  }

  return added
}

// ─────────────────────────────────────────────────────────────
// Policy Events (Kernel 불개입)
// ─────────────────────────────────────────────────────────────

fn onTaskSuccess(task_id) {
  RunningPool_remove(task_id)
  GLOBAL_TASKS_COMPLETED = GLOBAL_TASKS_COMPLETED + 1
  return POLICY_DECISION_PROCEED
}

fn onTaskFailure_withReplan(task_id, retry_count) {
  // Running Task는 제거
  RunningPool_remove(task_id)
  GLOBAL_TASKS_FAILED = GLOBAL_TASKS_FAILED + 1

  // 재시도 기회가 남았으면 Replan 시도
  if retry_count < 1 {
    GLOBAL_REPLANS_ATTEMPTED = GLOBAL_REPLANS_ATTEMPTED + 1

    // PlanDelta 적용: 복구 Task 추가
    applyPlanDelta_addTask("recovery-" + task_id)

    return POLICY_DECISION_REPLAN
  }

  return POLICY_DECISION_ABORT
}

// ─────────────────────────────────────────────────────────────
// Spawn Ready Tasks into Execution
// ─────────────────────────────────────────────────────────────

fn spawnReadyTasks() {
  while ReadyQueue_length() > 0 {
    if RunningPool_length() >= GLOBAL_PARALLEL_POLICY_MAX {
      break
    }

    let task_id = ReadyQueue_dequeue()
    if task_id == "" {
      break
    }

    RunningPool_add(task_id)
  }

  return RunningPool_length()
}

// ─────────────────────────────────────────────────────────────
// Test Utilities
// ─────────────────────────────────────────────────────────────

fn assert_true(actual, msg) {
  if actual {
    println("✓ " + msg)
    return true
  }
  println("✗ FAILED: " + msg)
  return false
}

fn assert_equal(actual, expected, msg) {
  if actual == expected {
    println("✓ " + msg)
    return true
  }
  println("✗ FAILED: " + msg)
  println("  Expected: " + expected)
  println("  Actual: " + actual)
  return false
}

// ─────────────────────────────────────────────────────────────
// TEST 1: Initial Parallel Execution (3 Running)
// ─────────────────────────────────────────────────────────────

fn test_01_initial_parallel() {
  println("")
  println("🧪 TEST 1: Initial Parallel Execution (3 tasks)")

  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")
  ReadyQueue_add("task-C")

  spawnReadyTasks()

  assert_equal(RunningPool_length(), 3, "3 tasks running")
  assert_equal(ReadyQueue_length(), 0, "Ready queue empty")

  println("✅ TEST 1 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 2: Task Completion (Slot Release)
// ─────────────────────────────────────────────────────────────

fn test_02_task_completion() {
  println("")
  println("🧪 TEST 2: Task Completion & Slot Release")

  GLOBAL_RUNNING_TASKS_COUNT = 0
  GLOBAL_READY_TASKS_COUNT = 0

  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")
  ReadyQueue_add("task-C")
  ReadyQueue_add("task-D")

  spawnReadyTasks()
  assert_equal(RunningPool_length(), 3, "Pool: 3 tasks")
  assert_equal(ReadyQueue_length(), 1, "Queue: 1 task")

  // Complete one task
  onTaskSuccess(GLOBAL_RUNNING_1)

  assert_equal(RunningPool_length(), 2, "Pool: 2 after completion")
  assert_equal(GLOBAL_TASKS_COMPLETED, 1, "Completed count: 1")

  println("✅ TEST 2 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 3: Failure During Parallel (Replan Initiated)
// ─────────────────────────────────────────────────────────────

fn test_03_failure_during_parallel() {
  println("")
  println("🧪 TEST 3: Failure During Parallel → Replan")

  GLOBAL_RUNNING_TASKS_COUNT = 0
  GLOBAL_READY_TASKS_COUNT = 0
  GLOBAL_REPLANS_ATTEMPTED = 0

  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")
  ReadyQueue_add("task-C")

  spawnReadyTasks()
  assert_equal(RunningPool_length(), 3, "Pool: 3 tasks")

  // Task B fails
  let decision = onTaskFailure_withReplan(GLOBAL_RUNNING_2, 0)

  assert_equal(decision, POLICY_DECISION_REPLAN, "Decision: Replan")
  assert_equal(GLOBAL_REPLANS_ATTEMPTED, 1, "Replan attempted: 1")
  assert_equal(RunningPool_length(), 2, "Pool: 2 (after removal)")
  assert_equal(ReadyQueue_length(), 1, "Queue: 1 (recovery task)")

  println("✅ TEST 3 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 4: Running Tasks Continue After Replan
// ─────────────────────────────────────────────────────────────

fn test_04_running_tasks_unaffected() {
  println("")
  println("🧪 TEST 4: Running Tasks Continue After Replan")

  GLOBAL_RUNNING_TASKS_COUNT = 0
  GLOBAL_READY_TASKS_COUNT = 0

  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")
  ReadyQueue_add("task-C")

  spawnReadyTasks()

  // Store original running tasks
  let taskA = GLOBAL_RUNNING_1
  let taskC = GLOBAL_RUNNING_3

  // Task B fails and triggers replan
  onTaskFailure_withReplan(GLOBAL_RUNNING_2, 0)

  // Verify A and C still in pool
  assert_equal(GLOBAL_RUNNING_1, taskA, "Task A still running")
  assert_equal(GLOBAL_RUNNING_2, taskC, "Task C still running")

  println("✅ TEST 4 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 5: Refill Pool After Replan
// ─────────────────────────────────────────────────────────────

fn test_05_refill_after_replan() {
  println("")
  println("🧪 TEST 5: Refill Pool After Replan")

  GLOBAL_RUNNING_TASKS_COUNT = 0
  GLOBAL_READY_TASKS_COUNT = 0

  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")
  ReadyQueue_add("task-C")

  spawnReadyTasks()

  onTaskFailure_withReplan(GLOBAL_RUNNING_2, 0)

  // Refill pool from ready queue
  spawnReadyTasks()

  assert_equal(RunningPool_length(), 3, "Pool refilled: 3 tasks")

  println("✅ TEST 5 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 6: Complete Replan + Parallel Cycle
// ─────────────────────────────────────────────────────────────

fn test_06_complete_replan_cycle() {
  println("")
  println("🧪 TEST 6: Complete Replan + Parallel Cycle")

  GLOBAL_RUNNING_TASKS_COUNT = 0
  GLOBAL_READY_TASKS_COUNT = 0
  GLOBAL_TASKS_COMPLETED = 0
  GLOBAL_TASKS_FAILED = 0
  GLOBAL_REPLANS_ATTEMPTED = 0

  // Initial 3 tasks
  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")
  ReadyQueue_add("task-C")

  spawnReadyTasks()

  // Failure → Replan
  onTaskFailure_withReplan(GLOBAL_RUNNING_2, 0)

  // Complete remaining tasks
  onTaskSuccess(GLOBAL_RUNNING_1)
  onTaskSuccess(GLOBAL_RUNNING_2)

  // Refill and complete recovery
  spawnReadyTasks()
  if RunningPool_length() > 0 {
    onTaskSuccess(GLOBAL_RUNNING_1)
  }

  assert_equal(GLOBAL_TASKS_FAILED, 1, "1 task failed")
  assert_equal(GLOBAL_REPLANS_ATTEMPTED, 1, "1 replan")

  println("✅ TEST 6 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 7: No Duplicate Execution
// ─────────────────────────────────────────────────────────────

fn test_07_no_duplicate_execution() {
  println("")
  println("🧪 TEST 7: No Duplicate Execution")

  GLOBAL_RUNNING_TASKS_COUNT = 0
  GLOBAL_READY_TASKS_COUNT = 0
  GLOBAL_TASKS_COMPLETED = 0

  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")

  spawnReadyTasks()

  // Complete task-A twice (verify no duplicate count)
  onTaskSuccess(GLOBAL_RUNNING_1)
  assert_equal(GLOBAL_TASKS_COMPLETED, 1, "Completed: 1")

  // Try removing again (should not double-count)
  let removed = RunningPool_remove(GLOBAL_RUNNING_1)
  assert_true(!removed, "Already removed: no duplicate")

  println("✅ TEST 7 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 8: Queue Coherence After Replan
// ─────────────────────────────────────────────────────────────

fn test_08_queue_coherence() {
  println("")
  println("🧪 TEST 8: Queue Coherence After Replan")

  GLOBAL_RUNNING_TASKS_COUNT = 0
  GLOBAL_READY_TASKS_COUNT = 0

  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")
  ReadyQueue_add("task-C")
  ReadyQueue_add("task-D")

  spawnReadyTasks()
  assert_equal(ReadyQueue_length(), 1, "Queue: 1 before replan")

  // Failure triggers replan (adds recovery task)
  onTaskFailure_withReplan(GLOBAL_RUNNING_2, 0)
  assert_equal(ReadyQueue_length(), 2, "Queue: 2 after replan")

  // Dequeue and verify order maintained
  let first = ReadyQueue_dequeue()
  assert_true(first != "", "First task dequeued")
  assert_equal(ReadyQueue_length(), 1, "Queue: 1 after dequeue")

  println("✅ TEST 8 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 9: Race Condition Free (Atomicity)
// ─────────────────────────────────────────────────────────────

fn test_09_atomicity_check() {
  println("")
  println("🧪 TEST 9: Atomicity Check (No Race Condition)")

  GLOBAL_RUNNING_TASKS_COUNT = 0
  GLOBAL_READY_TASKS_COUNT = 0

  ReadyQueue_add("task-A")
  ReadyQueue_add("task-B")
  ReadyQueue_add("task-C")

  spawnReadyTasks()

  // Simulate concurrent events
  onTaskSuccess(GLOBAL_RUNNING_1)
  spawnReadyTasks()

  // Verify consistency
  let total_tracked = RunningPool_length() + ReadyQueue_length() + GLOBAL_TASKS_COMPLETED

  assert_equal(total_tracked, 3, "Task count consistent: 3")

  println("✅ TEST 9 PASSED")
}

// ─────────────────────────────────────────────────────────────
// TEST 10: Integration Readiness
// ─────────────────────────────────────────────────────────────

fn test_10_integration_readiness() {
  println("")
  println("🧪 TEST 10: Integration Readiness Check")

  assert_equal(GLOBAL_PARALLEL_POLICY_MAX, 3, "MaxParallel: 3")

  // Verify all state tracking works
  assert_true(RunningPool_length() == 0, "Clean running pool")
  assert_true(ReadyQueue_length() == 0, "Clean ready queue")

  // Verify no race conditions were introduced
  assert_true(GLOBAL_TASKS_COMPLETED >= 0, "Completion counter valid")
  assert_true(GLOBAL_REPLANS_ATTEMPTED >= 0, "Replan counter valid")

  println("✅ TEST 10 PASSED")
}

// ─────────────────────────────────────────────────────────────
// Main Test Runner
// ─────────────────────────────────────────────────────────────

println("")
println("╔════════════════════════════════════════════════════════════╗")
println("║   🔒 v2.K.5 — Replan + Parallel Integration Stability     ║")
println("╚════════════════════════════════════════════════════════════╝")

test_01_initial_parallel()
test_02_task_completion()
test_03_failure_during_parallel()
test_04_running_tasks_unaffected()
test_05_refill_after_replan()
test_06_complete_replan_cycle()
test_07_no_duplicate_execution()
test_08_queue_coherence()
test_09_atomicity_check()
test_10_integration_readiness()

